import React from 'react';

import ButtonMyCards from '../../../../src/atomic/molecules/ButtonMyCards';
import { render, fireEvent } from '../../../util';

describe('ButtonMyCards', () => {
  const mockOnPressSecondVia = jest.fn();
  const mockOnPressCreateVirtualCard = jest.fn();

  beforeEach(() => {
    jest.clearAllMocks();
  });

  it('should render the "Solicitar 2ª via do cartão" button and handle press', () => {
    const screen = render(
      <ButtonMyCards
        canGenerateSecondVia
        isExistVirtualCard={false}
        onPressCanGenerateSecondVia={mockOnPressSecondVia}
        onPressCreateVirtualCard={mockOnPressCreateVirtualCard}
      />,
    );

    expect(screen.getByText('Solicitar 2ª via do cartão')).toBeTruthy();
    fireEvent.press(screen.getByText('Solicitar 2ª via do cartão'));
    expect(mockOnPressSecondVia).toHaveBeenCalledTimes(1);
  });

  it('should render the "Criar cartão virtual" button and handle press', () => {
    const screen = render(
      <ButtonMyCards
        canGenerateSecondVia={false}
        isExistVirtualCard
        onPressCanGenerateSecondVia={mockOnPressSecondVia}
        onPressCreateVirtualCard={mockOnPressCreateVirtualCard}
      />,
    );

    expect(screen.getByText('Criar cartão virtual')).toBeTruthy();
    fireEvent.press(screen.getByText('Criar cartão virtual'));
    expect(mockOnPressCreateVirtualCard).toHaveBeenCalledTimes(1);
  });

  it('should render null if neither conditions are met', () => {
    const screen = render(
      <ButtonMyCards
        canGenerateSecondVia={false}
